public class FloatDemo {
    public static void main(String[] args) {
        // CORRECT WAYS
        float pi1 = 3.14159f;    // With 'f' suffix
        float pi2 = 3.14159F;    // With 'F' suffix (uppercase)
        float pi3 = (float) 3.14159;  // Explicit cast

        // CORRECT: Double declaration (no suffix needed)
        double pi4 = 3.14159;
        double pi5 = 3.14159d;   // Optional 'd' suffix
        double pi6 = 3.14159D;  // Optional 'D' suffix

        // INCORRECT - Causes compilation error:
        // float pi7 = 3.14159;  // Error: incompatible types
        // float pi8 = 3.14159d; // Error: incompatible types

        System.out.println("Float values: " + pi1 + ", " + pi2 + ", " + pi3);
        System.out.println("Double values: " + pi4 + ", " + pi5 + ", " + pi6);
    }
}

public class PrecisionDemo {
    public static void main(String[] args) {
        double a = 0.1;
        double b = 0.2;
        double sum = a + b;

        System.out.println("a = " + a);
        System.out.println("b = " + b);
        System.out.println("a + b = " + sum);
        System.out.println("0.3 = " + 0.3);
        System.out.println("sum == 0.3: " + (sum == 0.3));  // FALSE!
        System.out.println("sum = " + sum);  // 0.30000000000000004

        // CORRECT WAY: Use tolerance-based comparison
        double epsilon = 0.0001;
        boolean approximatelyEqual = Math.abs(sum - 0.3) < epsilon;
        System.out.println("Approximately equal: " + approximatelyEqual);  // TRUE

        // Using Float for comparison
        float fa = 0.1f;
        float fb = 0.2f;
        float fsum = fa + fb;
        System.out.println("Float sum: " + fsum);
    }
}

public class SpecialValuesDemo {
    public static void main(String[] args) {
        // Infinity
        System.out.println("10.0 / 0.0 = " + (10.0 / 0.0));          // Infinity
        System.out.println("-10.0 / 0.0 = " + (-10.0 / 0.0));        // -Infinity
        System.out.println("Double.isInfinite(10.0/0.0): " + 
            Double.isInfinite(10.0 / 0.0));  // true

        // NaN
        System.out.println("0.0 / 0.0 = " + (0.0 / 0.0));            // NaN
        System.out.println("Math.sqrt(-1) = " + Math.sqrt(-1));      // NaN
        System.out.println("Double.isNaN(0.0/0.0): " + 
            Double.isNaN(0.0 / 0.0));  // true

        // NaN property: NaN is not equal to itself
        System.out.println("Double.NaN == Double.NaN: " + 
            (Double.NaN == Double.NaN));  // FALSE!
        System.out.println("Double.isNaN(Double.NaN): " + 
            Double.isNaN(Double.NaN));  // true

        // Negative zero
        System.out.println("-0.0 == 0.0: " + (-0.0 == 0.0));        // true
        System.out.println("1.0 / -0.0 = " + (1.0 / -0.0));          // -Infinity
    }
}

public class ScientificNotationDemo {
    public static void main(String[] args) {
        // Scientific notation with positive exponent
        double val1 = 1.23e5;    // 1.23 × 10^5 = 123000.0
        double val2 = 1.23E5;    // Uppercase E also works

        // Scientific notation with negative exponent
        double val3 = 1.23e-5;   // 1.23 × 10^-5 = 0.0000123
        double val4 = 1.23E-5;   // Works with uppercase

        // Large and small numbers
        double val5 = 6.022e23;  // Avogadro's number approx
        double val6 = 6.626e-34; // Planck's constant approx

        System.out.println("1.23e5 = " + val1);  // 123000.0
        System.out.println("1.23e-5 = " + val3); // 1.23E-5
        System.out.println("6.022e23 = " + val5); // 6.022E23
        System.out.println("6.626e-34 = " + val6); // 6.626E-34

        // Float with scientific notation
        float f1 = 1.23e5f;  // Must include 'f' suffix
        float f2 = 1.23e-5f; // Negative exponent with suffix
        System.out.println("Float 1.23e5f = " + f1);
    }
}
